// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.ir;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingSymbol;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingUniverse;
import org.junit.jupiter.api.Test;

class ScalarExprFactsTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void equalityToRdfTermIsFiniteAnchor() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSymbol symbol = universe.symbol("drug");
		IRI value = VF.createIRI("urn:drug:1");
		ScalarExpr expr = new ScalarExpr.Eq(new ScalarExpr.VarRef(symbol), new ScalarExpr.Constant(value));

		ScalarFacts facts = ScalarFacts.of(universe, expr);

		assertTrue(facts.isFiniteEqualityAnchor());
		assertFalse(facts.isFiniteInAnchor());
		assertTrue(facts.freeVars().contains(symbol));
		assertEquals(symbol, ScalarFacts.finiteAnchorVariable(expr));
		assertEquals(List.of(value), ScalarFacts.finiteAnchorValues(expr));
	}

	@Test
	void inAnchorPreservesDuplicateConstants() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSymbol symbol = universe.symbol("drug");
		IRI value = VF.createIRI("urn:drug:1");
		ScalarExpr expr = new ScalarExpr.In(new ScalarExpr.VarRef(symbol),
				List.of(new ScalarExpr.Constant(value), new ScalarExpr.Constant(value)));

		ScalarFacts facts = ScalarFacts.of(universe, expr);

		assertTrue(facts.isFiniteInAnchor());
		assertEquals(List.of(value, value), ScalarFacts.finiteAnchorValues(expr));
	}

	@Test
	void boundDoesNotErrorOnUnbound() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSymbol symbol = universe.symbol("x");

		ScalarFacts facts = ScalarFacts.of(universe, new ScalarExpr.Bound(symbol));

		assertFalse(facts.mayErrorOnUnbound());
		assertTrue(facts.totalWhenAssured());
	}
}
